#include <vector>
#include <algorithm>

long long solve(std::vector<long long> piles) {
    std::sort(piles.begin(), piles.end());
    long long sum = 0;
    int n = piles.size();
    for (int i = 0; i < n; i += 3) {
        sum += piles[i + 1];
    }
    return sum;
}
